// 获取 AI Agent 节点处理后的所有结果
const allItems = $input.all();

// 1. 初始化统计变量
let targetCount = 0;   // 目标岗位计数
let suitableCount = 0; // 适合岗位计数
let processedCount = allItems.length;

// 2. 预处理数据：提取 JSON 并转换分数
let jobs = allItems.map(item => {
  const d = item.json;
  // 确保分数是数字类型
  const score = parseInt(d.ai_comp_score) || 0;

  // 统计标签逻辑
  const labels = d.ai_labels || "";
  if (labels.includes("目标岗位")) targetCount++;
  if (labels.includes("适合岗位")) suitableCount++;

  return { ...d, score };
});

// 3. 排序逻辑：按分数从高到低排列
jobs.sort((a, b) => b.score - a.score);

// 4. 获取前 5 个岗位
const top5 = jobs.slice(0, 5);

// 5. 构建汇总列表
let summaryList = top5.map((job, index) => {
  return `${index + 1}. ${job.title} (得分: ${job.ai_comp_score})\n` +
         `**公司**: ${job.company}\n` +
         `**发布时间**: ${job.posted_at || 'N/A'}\n` +
         `**地点**: ${job.location || 'N/A'}\n` +
         `**核心要求**: ${job.ai_requirements}\n` +
         `**职位链接**: [点击查看](${job.url})\n`;
}).join('\n---\n');

// 6. 返回最终结果
return {
  total_processed: processedCount,
  target_total: targetCount,
  suitable_total: suitableCount,
  summary_report: `## 🚀 今日求职日报 (${$now.toFormat('yyyy-MM-dd')})\n\n` +
                  `今天共处理了 **${processedCount}** 个岗位：\n` +
                  `🎯 **目标岗位**: ${targetCount} 个\n` +
                  `✅ **适合岗位**: ${suitableCount} 个\n\n` +
                  `---\n\n` +
                  `## 🔥 匹配度最高的前 5 个机会\n\n` +
                  (summaryList || "今天没有找到合适的岗位推荐。")
};
